import click

@click.command()
@click.argument('name')
def greet(name):
    """A simple greeting CLI."""
    click.echo(f"Hello, {name}!")

if __name__ == '__main__':
    greet()

import click
import os
import tomllib
from pathlib import Path

CONFIG_PATH = Path.home() / ".config" / "mytool" / "config.toml"

def load_config():
    if CONFIG_PATH.exists():
        with open(CONFIG_PATH, "rb") as f:
            return tomllib.load(f)
    return {}

@click.command()
@click.option('--output', default=None, help='Output directory')
def run(output):
    config = load_config()
    out = (
        output
        or os.environ.get("MYTOOL_OUTPUT")
        or config.get("output")
        or "./dist"
    )
    click.echo(f"Output: {out}")

@click.group()
@click.pass_context
def cli(ctx):
    """MyTool — a zero-config developer CLI."""
    ctx.ensure_object(dict)
    ctx.obj['config'] = load_config()

@cli.command()
@click.pass_context
def build(ctx):
    """Build the project."""
    click.echo("Building...")

@cli.command()
@click.pass_context
def deploy(ctx):
    """Deploy to production."""
    click.echo("Deploying...")
